import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";var i=JSON.parse(`{"title":"开机上电","description":"","frontmatter":{"title":"开机上电","order":10},"headers":[],"relativePath":"kernel/linux/power/boot.md","filePath":"kernel/linux/power/boot.md"}`),a={name:`kernel/linux/power/boot.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="开机上电" tabindex="-1">开机上电 <a class="header-anchor" href="#开机上电" aria-label="Permalink to “开机上电”">​</a></h1><p>开机流程涉及硬件态向内核态的转化，操作系统是运行在硬件上的一个程序，其加载运行也是一个复杂的过程，一旦操作系统运行成功，应用层的软件便可以由操作系统加载和运行，乘上操作系统的快车，利用操作系统提供的 API 便捷地使用硬件完成业务需求。</p><h2 id="供电" tabindex="-1">供电 <a class="header-anchor" href="#供电" aria-label="Permalink to “供电”">​</a></h2><p>在硬件平台通电时，主板等周边设备上的小型专用处理器将优先工作。其中挂载在 CPU 总线上的小型控制器 EC（Embedded Controller）负责计算机的电源管理工作。EC 控制电源供应单元为硬件系统供电，系统各部分进入各自的供电流程，包括 CPU、内存、南北桥芯片等。</p><blockquote><p>周边设备的控制器芯片不承担主要的计算任务，但会帮助协调各个硬件之间的工作。</p></blockquote><p>各个硬件的供电顺序有所先后，一般顺序是：CPU、内存、南北桥、扩展卡和外围设备、启动存储等。电源控制单元在确保电源供应一切顺利后，向 EC 发出信号表示供电完毕。供电成功后，EC 通知主板上的各个芯片组，正式开启计算机的启动流程。</p><p>首先，南北桥进行交互：</p><ol><li>南桥向北桥发出正常信号</li><li>北桥收到南桥信号，并向 CPU 发送正常信号</li><li>CPU 开始工作</li></ol><blockquote><p>供电单元可以进行交流电到直流电的转化，并保持电源电压的稳定。</p></blockquote><h2 id="bios-uefi-寻找-boot-loader" tabindex="-1">BIOS/UEFI 寻找 Boot Loader <a class="header-anchor" href="#bios-uefi-寻找-boot-loader" aria-label="Permalink to “BIOS/UEFI 寻找 Boot Loader”">​</a></h2><p>CPU 开始工作后的第一个程序是 BIOS/UEFI 程序，它是主板上的固件。BIOS 程序会：</p><ol><li>扫描和检查设备</li><li>初始化硬件系统（主板、内存、CPU、显卡等）</li><li>确保设备能够正常工作（POST - Power-On Self Test）</li><li>为内存条和 MMIO 设备分配地址空间</li><li>将地址空间连成连续的数组空间（地址位数取决于机器位宽，通常为 32 位或 64 位）</li></ol><p>在硬件检查完毕后，硬件信息将会被放置在物理内存空间中的一些约定俗成的位置，BIOS/UEFI 程序尝试依次从多个外部存储设备中加载 Boot Loader 程序到内存中。如果某个设备中没有找到，则尝试从下一个存储设备加载。一旦加载成功，计算机的执行权就移交给 Boot Loader。</p><p>BIOS 加载 Boot Loader 时，从外部存储设备的启动扇区（MBR - Master Boot Record）加载，并将其放置到内存中的约定区域。BIOS 查找 Boot Loader 程序的顺序可能如下：</p><ul><li>硬盘</li><li>USB</li><li>CDROM</li><li>网卡（pxe 启动）</li></ul><p>BIOS 通常提供基于终端的配置界面，允许用户自定义引导过程，例如修改启动介质的优先级。</p><blockquote><p>一些硬件层面的功能（如网卡的 SR-IOV 功能）不一定会被启用。如需启用，需要重启机器并提前修改 BIOS 配置。</p></blockquote><h2 id="boot-loader-加载操作系统" tabindex="-1">Boot Loader 加载操作系统 <a class="header-anchor" href="#boot-loader-加载操作系统" aria-label="Permalink to “Boot Loader 加载操作系统”">​</a></h2><p>Boot Loader 是存放在操作系统镜像盘中约定区域的一段程序。它被 BIOS 程序加载并执行，负责：</p><ol><li>把操作系统的文件加载到内存中</li><li>初始化操作系统</li><li>将计算机的执行权移交给操作系统</li></ol><blockquote><p>Boot Loader 执行时，CPU 处于 Real 模式，只能访问 1MB 的内存空间，没有内存保护。Boot Loader 利用硬盘的分区表、文件系统信息和操作系统核心文件，实现从实模式到保护模式的切换，以及从硬盘到内存的数据传输。</p></blockquote><p>Boot Loader 根据 MBR 中的磁盘分区信息，找到活动分区（操作系统文件所在的分区），然后：</p><ol><li>找到操作系统可执行文件</li><li>加载操作系统到指定的内存区域</li><li>跳转 CPU 到该区域，开始执行操作系统</li></ol><p>常见的 Boot Loader 实现包括：</p><ul><li>GRUB（广泛用于 x86 平台）</li><li>UBoot（广泛用于 arm 嵌入式开发板）</li><li>LILO</li><li>NTLDR</li><li>BOOTMGR</li></ul><p>在 Linux 文件系统中，Boot Loader 通常位于<code>/boot</code>目录下。</p><h3 id="boot-params-启动协议" tabindex="-1">boot_params 启动协议 <a class="header-anchor" href="#boot-params-启动协议" aria-label="Permalink to “boot_params 启动协议”">​</a></h3><p>TODO:</p><h2 id="操作系统启动-从汇编到-c" tabindex="-1">操作系统启动：从汇编到 C <a class="header-anchor" href="#操作系统启动-从汇编到-c" aria-label="Permalink to “操作系统启动：从汇编到 C”">​</a></h2><p>当 Boot Loader 将内核镜像加载到内存并移交控制权后，内核的启动流程正式展开。整个流程可以划分为四个阶段，从 16 位实模式逐步过渡到 64 位长模式，最终进入架构无关的通用内核初始化。</p><h3 id="阶段一-实模式启动-arch-x86-boot" tabindex="-1">阶段一：实模式启动 (<code>arch/x86/boot/</code>) <a class="header-anchor" href="#阶段一-实模式启动-arch-x86-boot" aria-label="Permalink to “阶段一：实模式启动 (arch/x86/boot/)”">​</a></h3><p>内核入口 <code>_start</code> 位于 <code>arch/x86/boot/header.S:246</code>，Boot Loader 跳转到这里时 CPU 还处于 16 位实模式。<code>header.S</code> 中定义了与引导程序之间的协议头（<code>hdr</code>），包含启动参数、载荷位置等关键信息，由 <code>setup.ld</code> 链接脚本约束整个 setup 段不超过 32KB。</p><p>实模式主函数 <code>main()</code> 位于 <code>arch/x86/boot/main.c:133</code>，负责三件事：通过 BIOS E820 中断检测物理内存布局、设置视频模式、检测 CPU 特性。之后 <code>go_to_protected_mode()</code>（<code>pm.c:103</code>）开启 A20 地址线、设置 GDT/IDT、切换到 32 位保护模式。这一步的标志性动作是通过 <code>pmjump.S</code> 执行一次远跳转，CS 寄存器被加载为保护模式代码段选择子，CPU 正式进入保护模式。</p><h3 id="阶段二-解压-stub-arch-x86-boot-compressed" tabindex="-1">阶段二：解压 stub (<code>arch/x86/boot/compressed/</code>) <a class="header-anchor" href="#阶段二-解压-stub-arch-x86-boot-compressed" aria-label="Permalink to “阶段二：解压 stub (arch/x86/boot/compressed/)”">​</a></h3><p>进入保护模式后，执行流到达 <code>head_64.S:82</code> 的 <code>startup_32</code>。这个 32 位入口负责建立早期的页表结构，启用长模式（64 位）。随后 <code>startup_64</code>（行 278）作为 64 位入口，完成自定位、处理 5 级分页和 SEV 加密等初始化工作。</p><p>重定位完成后，调用 <code>extract_kernel()</code>（<code>misc.c:407</code>）执行内核解压。这个函数先通过 KASLR 随机化内核加载地址，然后根据压缩格式（gzip/xz/zstd）解压内核镜像，最后解析 ELF 格式将其加载到目标内存位置。解压完成后跳转到内核主体的入口。</p><p>bzImage 的构建过程反映了这个阶段的产物组织方式：</p><ul><li>内核源码编译为 <code>vmlinux</code>（未压缩 ELF）</li><li>strip 得到 <code>vmlinux.bin</code>，压缩为 <code>vmlinux.bin.gz</code></li><li>通过 <code>piggy.S</code> 将压缩数据嵌入，与解压 stub 链接为 <code>compressed/vmlinux</code></li><li><code>objcopy</code> 提取为 <code>vmlinux.bin</code>，与实模式 setup.bin 合并，最终生成 <code>bzImage</code></li></ul><h3 id="阶段三-内核主体入口-arch-x86-kernel" tabindex="-1">阶段三：内核主体入口 (<code>arch/x86/kernel/</code>) <a class="header-anchor" href="#阶段三-内核主体入口-arch-x86-kernel" aria-label="Permalink to “阶段三：内核主体入口 (arch/x86/kernel/)”">​</a></h3><p>解压完成后，执行流到达 <code>arch/x86/kernel/head_64.S:38</code> 的 <code>startup_64</code>——这是内核本体的第一个入口。BSP（启动 CPU）在此设置 GDT/IDT、修正页表、配置 CR4/EFER 等控制寄存器。<code>common_startup_64</code>（行 198）是 BSP 和 AP（应用处理器）的共用路径，负责配置 per-CPU 栈和 APIC ID 查找。</p><p><code>initial_code</code>（行 479）是一个函数指针，指向 <code>x86_64_start_kernel()</code>——内核执行的第一个 C 函数。这个函数（<code>arch/x86/kernel/head64.c:222</code>）清理早期页表、初始化 KASAN、拷贝启动参数、加载 CPU 微码，最后调用 <code>start_kernel()</code> 进入架构无关的通用初始化。</p><h3 id="阶段四-通用内核初始化-init-main-c" tabindex="-1">阶段四：通用内核初始化 (<code>init/main.c</code>) <a class="header-anchor" href="#阶段四-通用内核初始化-init-main-c" aria-label="Permalink to “阶段四：通用内核初始化 (init/main.c)”">​</a></h3><p><code>start_kernel()</code>（<code>init/main.c:1008</code>）是内核主体逻辑的入口。它按严格的顺序启动各个核心子系统：</p><ol><li><code>setup_arch()</code>：ACPI 解析、E820 内存映射建立、SMP 初始化等架构相关设置</li><li><code>trap_init()</code>：中断和异常处理框架</li><li><code>sched_init()</code>：调度器初始化</li><li><code>console_init()</code>：控制台可用（此后内核可以通过 printk 输出日志）</li><li>其他子系统：定时器、RCU、cgroup、VFS 等依次初始化</li></ol><p>所有子系统初始化完成后，<code>rest_init()</code>（行 714）创建 PID 1（<code>kernel_init</code>，最终执行 <code>/sbin/init</code>）和 PID 2（<code>kthreadd</code>，内核线程守护者），BSP 自身退化为 idle 进程。至此，内核完成全部初始化，用户空间的第一个进程开始运行。</p><h3 id="早期内存管理的建立" tabindex="-1">早期内存管理的建立 <a class="header-anchor" href="#早期内存管理的建立" aria-label="Permalink to “早期内存管理的建立”">​</a></h3><p>在 <code>start_kernel()</code> 之前，CPU 已经有了可用的页表——但这些早期页表只映射了内核镜像本身（约几十 MB），仅够内核勉强执行。<code>start_kernel()</code> 中的内存初始化子系统需要从零构建完整的内存管理基础设施。</p><p>第一步是摸清家底。<code>setup_arch()</code> 通过 BIOS 提供的 E820 表获取物理内存分布，调用 <code>e820__memblock_setup()</code> 填充 memblock 早期分配器，此后 <code>memblock_alloc()</code> 可用。接着 <code>init_mem_mapping()</code> 为全部物理 RAM 建立直接映射页表（替换早期临时页表），最后将 <code>swapper_pg_dir</code> 加载到 CR3。</p><p>第二步是建立 zone/node 结构。<code>free_area_init()</code> 将物理内存划分为 ZONE_DMA（ISA DMA 用）、ZONE_DMA32（32 位设备 DMA 用）和 ZONE_NORMAL（普通内存）三个区域。同时通过 <code>sparse_init()</code> 分配每个内存 section 的 <code>struct page</code> 数组（vmemmap），由 <code>memmap_init()</code> 逐个初始化每个 <code>struct page</code>。</p><p>第三步是启动伙伴分配器。<code>mm_core_init()</code> 调用 <code>memblock_free_all()</code> 将 memblock 中记录的空闲页全部移交给伙伴系统——这是最关键的转变：从&quot;记录哪些物理页可用&quot;的早期分配器切换到&quot;按 2^n 页框管理&quot;的伙伴系统。此后 <code>alloc_pages()</code> 和 <code>__get_free_pages()</code> 可用。紧接着 <code>kmem_cache_init()</code> 启动 SLUB 分配器（<code>kmalloc()</code> 可用），<code>vmalloc_init()</code> 启动 vmalloc 分配器。</p><p>早期页表与 <code>start_kernel()</code> 建立的页表之间存在本质差距：</p><table tabindex="0"><thead><tr><th>维度</th><th>早期页表</th><th>start_kernel 建立的页表</th></tr></thead><tbody><tr><td>映射范围</td><td>仅内核镜像（约几十 MB）</td><td>所有物理 RAM</td></tr><tr><td>分配能力</td><td>无，全靠 brk 预留缓冲区</td><td>memblock → buddy → slab 三级</td></tr><tr><td>zone 概念</td><td>无</td><td>DMA/DMA32/NORMAL 分区</td></tr><tr><td>struct page</td><td>无</td><td>每个物理页都有元数据</td></tr><tr><td>NUMA 感知</td><td>无</td><td>按节点组织内存</td></tr></tbody></table><p>简单来说，早期页表是让内核能跑起来的脚手架，<code>start_kernel()</code> 要在此基础上建立起整栋内存管理的大厦。</p><h3 id="cr3-切换时间线" tabindex="-1">CR3 切换时间线 <a class="header-anchor" href="#cr3-切换时间线" aria-label="Permalink to “CR3 切换时间线”">​</a></h3><p>从 Boot Loader 到 <code>start_kernel()</code>，CR3 寄存器经历了多次切换，每一次都对应着页表结构的重大变化：</p><ol><li>解压器 <code>startup_32</code> 在汇编中手动构建 4GB 恒等映射的三级页表（L4→L3→L2，用 2MB 大页），写入 CR3</li><li><code>initialize_identity_mappings()</code> 读取当前 CR3，复用或新建顶层页表，映射内核映像和命令行等区域</li><li>内核本体 <code>startup_64</code> 调用 <code>__startup_64()</code> 修正 <code>early_top_pgt</code>（处理 KASLR 偏移），写入 CR3 切换到修正后的页表</li><li><code>x86_64_start_kernel()</code> 调用 <code>reset_early_page_tables()</code> 清理早期页表中的恒等映射，构建 <code>init_top_pgt</code>（即最终的 <code>swapper_pg_dir</code>）</li><li><code>start_kernel()</code> 中 <code>init_mem_mapping()</code> 为全部物理内存建立完整直接映射，最终加载到 CR3</li></ol><p>关键的静态页表数据结构定义在 <code>head_64.S</code> 中：<code>early_top_pgt</code> 是启动过渡 PGD（仅 entry[511] 非零，指向 <code>level3_kernel_pgt</code>），<code>init_top_pgt</code> 是最终运行时 PGD（初始全零，逐步填充），<code>level2_kernel_pgt</code> 用 2MB 大页映射内核的 text+data+bss 段。最初的 PGD 由解压器汇编代码从零构建，内核本体的 <code>early_top_pgt</code> 则在编译时静态定义、启动时由 <code>__startup_64()</code> 做 KASLR 修正后加载。</p><h2 id="一号进程启动" tabindex="-1">一号进程启动 <a class="header-anchor" href="#一号进程启动" aria-label="Permalink to “一号进程启动”">​</a></h2><p>内核初始化的最后一步是 <code>rest_init()</code> 创建 PID 1。这个进程在 Linux 系统中具有极其特殊的地位——它是用户空间启动的第一个进程，由内核直接创建，始终拥有进程号 1。PID 1 负责启动系统服务、守护进程以及用户登录环境，决定了系统的运行模式和服务框架。在现代 Linux 发行版中，PID 1 通常是 systemd，它通过单元文件管理所有系统服务的启动顺序和依赖关系。</p>`,59)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};